  const ts = Date.now();
  // Append a short random suffix so two runs that start in the same
  // millisecond don't merge into a single dir and race their status.json
  // writes. 6 chars from a 36-symbol alphabet = 36^6 = ~2.2B; collision
  // within the same ms is negligible for a CLI.
  const rand = Math.floor(Math.random() * 36 ** 6).toString(36).padStart(6, '0');
  const sanitized = opts.label ? sanitizeRunLabel(opts.label) : '';
